def transform(input_data):
    rows = input_data if isinstance(input_data, list) else []
    normalized = []
    for row in rows:
        name = str(row.get('Name', '')).strip()
        origin = str(row.get('Origin', 'unknown')).strip() or 'unknown'
        if not name:
            continue
        normalized.append({
            'name': name,
            'origin': origin,
            'mpg': row.get('Miles_per_Gallon'),
            'hp': row.get('Horsepower'),
            'year': str(row.get('Year', ''))[:4],
        })
    return normalized
